namespace sv_302460ed89f64d25bbb9a5c2db29f75d.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service holding per-circuit theme state.
/// All interactive components in the same circuit share one instance.
/// </summary>
public sealed class ThemeService
{
    public ThemeMode Mode { get; private set; } = ThemeMode.System;
    public string AccentColor { get; private set; } = "#0d6efd";

    public event Action? OnChange;

    public void SetMode(ThemeMode mode)
    {
        if (Mode == mode) return;
        Mode = mode;
        OnChange?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        OnChange?.Invoke();
    }

    public void SetTheme(ThemeMode mode, string accentColor)
    {
        var changed = Mode != mode || AccentColor != accentColor;
        Mode = mode;
        AccentColor = accentColor;
        if (changed) OnChange?.Invoke();
    }
}

@* Interactive island that lives in the static layout header *@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<span class="badge rounded-pill" style="background-color: @ThemeService.AccentColor; color: white;">
    @ThemeService.Mode
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

@* Quick toggle — can be dropped into the sidebar or any interactive page *@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<div class="d-flex align-items-center gap-2">
    <button class="btn btn-sm @ButtonClass" @onclick="CycleTheme" title="Toggle theme">
        @Icon @ThemeService.Mode
    </button>
</div>

@code {
    private string Icon => ThemeService.Mode switch
    {
        ThemeMode.Light  => "☀️",
        ThemeMode.Dark   => "🌙",
        _                => "💻"
    };

    private string ButtonClass => ThemeService.Mode switch
    {
        ThemeMode.Dark => "btn-dark",
        _              => "btn-outline-secondary"
    };

    private void CycleTheme()
    {
        var next = ThemeService.Mode switch
        {
            ThemeMode.Light  => ThemeMode.Dark,
            ThemeMode.Dark   => ThemeMode.System,
            _                => ThemeMode.Light
        };
        ThemeService.SetMode(next);
    }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@ThemeService.Mode"
                    @onchange="OnModeChanged">
                @foreach (var mode in Enum.GetValues<ThemeMode>())
                {
                    <option value="@mode">@mode</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@ThemeService.AccentColor"
                       @onchange="OnColorChanged" />
                <span class="text-muted">@ThemeService.AccentColor</span>
            </div>
        </div>

        <div class="mt-4 p-3 rounded" style="background-color: @ThemeService.AccentColor; color: white;">
            Preview — @ThemeService.Mode mode, accent @ThemeService.AccentColor
        </div>
    </div>
</div>

@code {
    private void OnModeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<ThemeMode>(e.Value?.ToString(), out var mode))
        {
            ThemeService.SetMode(mode);
        }
    }

    private void OnColorChanged(ChangeEventArgs e)
    {
        ThemeService.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");
    }

    protected override void OnInitialized()
    {
        ThemeService.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        ThemeService.OnChange -= StateHasChanged;
    }
}

